// Jedno źródło prawdy.
// UWAGA: SAS tokeny wygasają — przed wdrożeniem produkcyjnym zastąp je
// tokenami bez daty wygaśnięcia lub przejdź na Managed Identity.
return [{ json: {
  tolerancePct: 0.5,
  criticalMultiplier: 4,
  trackCurrencies: ['EUR','USD','GBP','CHF'],
  gotenbergUrl: 'http://gotenberg:3000',
  blobBase: 'https://genaimbank20146287194.blob.core.windows.net/azureml',
  recipients: 'risk-team@example.com',
  fileSource: 'blob',
  machines: [
    {
      name: 'vm-1',
      blob: 'https://genaimbankdp8236668111.blob.core.windows.net/azureml/fx/transactions-vm1.csv?sp=rw&st=2026-06-25T12:09:50Z&se=2026-06-25T20:24:50Z&spr=https&sv=2026-02-06&sr=c&sig=zCTeBKYo0ZGhkBWRN6MKMspBFC43p9Jyp284JiSZYWE%3D'
    },
    {
      name: 'vm-2',
      blob: 'https://genaimbank20146287194.blob.core.windows.net/azureml/fx/transactions-vm2.csv?sp=rw&st=2026-06-25T12:07:34Z&se=2026-06-25T20:22:34Z&spr=https&sv=2026-02-06&sr=c&sig=a1%2FNiDmjegadnGn3PQoY%2B53xZrJQkSJ%2FDODiHw%2FE40A%3D'
    }
  ],
  platforms: [
    { name: 'NBP', url: 'https://api.nbp.pl/api/exchangerates/tables/A?format=json' },
    { name: 'ECB', url: 'https://api.frankfurter.app/latest?from=EUR' }
  ]
}}];

// JSON.parse/stringify wymusza plain objects — unikamy n8n Proxy, który wewnętrznie ma klucz 'json'.
const machines = JSON.parse(JSON.stringify($('Set Config').first().json.machines));
return machines.map(m => ({ json: { name: m.name, blob: m.blob } }));

// JSON.parse/stringify na danych z innych węzłów → plain objects, brak Proxy.
const machineNames = JSON.parse(JSON.stringify($('Machines List').all().map(i => i.json.name)));
const inputItems = $input.all();
const rows = [];
for (let i = 0; i < inputItems.length; i++) {
  const csv = String(inputItems[i].json.data || '');
  const machineName = machineNames[i] || ('machine-' + (i + 1));
  if (!csv.trim()) continue;
  const lines = csv.trim().split('\n');
  for (const line of lines.slice(1)) {
    const parts = line.split(',');
    if (parts.length < 6 || !parts[0].trim()) continue;
    const [txId, ts, pair, amount, rate, counterparty] = parts;
    rows.push({ json: {
      machine: String(machineName),
      txId: txId.trim(),
      ts: ts.trim(),
      pair: pair.trim(),
      amount: Number(amount.trim()),
      rate: Number(rate.trim()),
      counterparty: (counterparty || '').trim()
    }});
  }
}
return rows;

// Każda platforma -> wspólny format { platform, pair: 'XXX/PLN', rate, ts }.
// Wylicza kursy krzyżowe do PLN, aby NBP i ECB pokrywały te same pary.
const now = $now.toISO();
const want = ($('Set Config').first().json.trackCurrencies) || ['EUR','USD','GBP','CHF'];
const out = [];
for (const item of $input.all()) {
  const b = item.json;
  // --- NBP (tabela A): [{ effectiveDate, rates:[{code, mid}] }] albo pojedynczy obiekt tabeli ---
  const nbpTables = Array.isArray(b)
    ? b
    : (b.rates && Array.isArray(b.rates) && b.rates[0] && 'code' in b.rates[0]) ? [b] : null;
  if (nbpTables) {
    for (const t of nbpTables) {
      for (const r of t.rates) {
        if (want.includes(r.code)) out.push({ json: { platform: 'NBP', pair: r.code + '/PLN', rate: r.mid, ts: t.effectiveDate || now } });
      }
    }
    continue;
  }
  // --- Frankfurter/ECB (base=EUR): { base:'EUR', date, rates:{ USD, PLN, ... } } ---
  if (b.rates && b.base) {
    const pln = b.rates.PLN;
    const ts = b.date || now;
    if (pln != null) {
      if (want.includes('EUR')) out.push({ json: { platform: 'ECB', pair: 'EUR/PLN', rate: pln, ts } });
      for (const C of want) {
        if (C === 'EUR') continue;
        const eurPerC = b.rates[C];
        if (eurPerC) out.push({ json: { platform: 'ECB', pair: C + '/PLN', rate: pln / eurPerC, ts } });
      }
    }
    continue;
  }
  // --- generyczna platforma: { platform, pair, rate, ts } ---
  if (b.pair && b.rate != null) out.push({ json: { platform: b.platform || 'OTHER', pair: b.pair, rate: b.rate, ts: b.ts || now } });
}
return out;

// Uzgodnienie: odchylenie kursu transakcji od każdej platformy (najbliższy czasowo kurs).
const txs = $('Parse & Normalize TX').all().map(i => i.json);
const rates = $('Normalize Rates').all().map(i => i.json);
const cfg = $('Set Config').first().json;
const tol = cfg.tolerancePct ?? 0.5;
const critX = cfg.criticalMultiplier ?? 4;
const platforms = [...new Set(rates.map(r => r.platform))];
function refRate(pair, platform, ts) {
  const c = rates.filter(r => r.pair === pair && r.platform === platform);
  if (!c.length) return null;
  c.sort((a, b) => Math.abs(new Date(a.ts) - new Date(ts)) - Math.abs(new Date(b.ts) - new Date(ts)));
  return c[0].rate;
}
const out = [];
for (const t of txs) {
  const row = { machine: t.machine, txId: t.txId, pair: t.pair, ts: t.ts, usedRate: t.rate, refs: {}, maxDeviationPct: 0, worstPlatform: null, severity: 'OK' };
  for (const p of platforms) {
    const rr = refRate(t.pair, p, t.ts);
    if (rr == null) { row.refs[p] = null; continue; }
    const dev = ((t.rate - rr) / rr) * 100;
    row.refs[p] = { rate: Math.round(rr * 1e6) / 1e6, deviationPct: Math.round(dev * 1e4) / 1e4 };
    if (Math.abs(dev) > Math.abs(row.maxDeviationPct)) { row.maxDeviationPct = Math.round(dev * 1e4) / 1e4; row.worstPlatform = p; }
  }
  const ad = Math.abs(row.maxDeviationPct);
  row.severity = ad > tol * critX ? 'CRITICAL' : ad > tol ? 'WARNING' : 'OK';
  out.push({ json: row });
}
return out;

// Wielostronicowy HTML (page-break per sekcja). Pełna wersja opisana w README.md.
const rows = $input.all().map(i => i.json);
const cfg = $('Set Config').first().json;
const ts = $now.toISO();
const byMachine = {};
for (const r of rows) (byMachine[r.machine] ??= []).push(r);
const crit = rows.filter(r => r.severity === 'CRITICAL');
const warn = rows.filter(r => r.severity === 'WARNING');
const fmt = n => (n > 0 ? '+' : '') + Number(n).toFixed(4) + '%';
const css = '<style>body{font-family:system-ui,Arial;color:#0f172a;margin:0}.page{padding:32px;min-height:100vh;box-sizing:border-box}@media print{.page{page-break-after:always}}h1{margin:0 0 4px}table{width:100%;border-collapse:collapse;font-size:12px}th,td{border:1px solid #cbd5e1;padding:6px 8px;text-align:left}.crit{color:#b91c1c;font-weight:700}.warn{color:#b45309}.ok{color:#15803d}.kpi{display:inline-block;margin-right:24px;font-size:20px;font-weight:700}</style>';
const row = r => '<tr><td>' + r.txId + '</td><td>' + r.pair + '</td><td>' + r.usedRate + '</td><td>' + (r.worstPlatform ?? '—') + '</td><td class="' + r.severity.toLowerCase() + '">' + fmt(r.maxDeviationPct) + '</td><td class="' + r.severity.toLowerCase() + '">' + r.severity + '</td></tr>';
let html = css + '<div class="page"><h1>Raport rozbieżności kursowych</h1><div>Wygenerowano: ' + ts + ' · próg ' + cfg.tolerancePct + '%</div><hr/><div class="kpi">Transakcje: ' + rows.length + '</div><div class="kpi warn">WARNING: ' + warn.length + '</div><div class="kpi crit">CRITICAL: ' + crit.length + '</div><p>Maszyny: ' + Object.keys(byMachine).join(', ') + '</p></div>';
for (const [m, list] of Object.entries(byMachine)) {
  html += '<div class="page"><h1>Maszyna: ' + m + '</h1><table><thead><tr><th>txId</th><th>Para</th><th>Kurs użyty</th><th>Najgorsza platforma</th><th>Maks. odchylenie</th><th>Status</th></tr></thead><tbody>' + list.map(row).join('') + '</tbody></table></div>';
}
html += '<div class="page"><h1>Załącznik — przekroczenia CRITICAL</h1><table><thead><tr><th>Maszyna</th><th>txId</th><th>Para</th><th>Platforma</th><th>Odchylenie</th></tr></thead><tbody>' + crit.map(r => '<tr><td>' + r.machine + '</td><td>' + r.txId + '</td><td>' + r.pair + '</td><td>' + r.worstPlatform + '</td><td class="crit">' + fmt(r.maxDeviationPct) + '</td></tr>').join('') + '</tbody></table></div>';
return [{ json: { generatedAt: ts, total: rows.length, critical: crit.length, warning: warn.length, fileName: 'report-' + ts.slice(0,10) + '.pdf', html } }];

// Zamienia pole json.html na plik binarny 'index.html' dla Gotenberga.
const item = $input.first();
const html = item.json.html || '';
const bin = await this.helpers.prepareBinaryData(Buffer.from(html, 'utf8'), 'index.html', 'text/html');
return [{ json: item.json, binary: { 'index.html': bin } }];
